from __future__ import annotations

import logging
import ssl

import socksio

from .._backends.sync import SyncBackend
from .._backends.base import NetworkBackend, NetworkStream
from .._exceptions import ConnectionNotAvailable, ProxyError
from .._models import URL, Origin, Request, Response, enforce_bytes, enforce_url
from .._ssl import default_ssl_context
from .._synchronization import Lock
from .._trace import Trace
from .connection_pool import ConnectionPool
from .http11 import HTTP11Connection
from .interfaces import ConnectionInterface

logger = logging.getLogger("httpcore.socks")


AUTH_METHODS = {
    b"\x00": "NO AUTHENTICATION REQUIRED",
    b"\x01": "GSSAPI",
    b"\x02": "USERNAME/PASSWORD",
    b"\xff": "NO ACCEPTABLE METHODS",
}

REPLY_CODES = {
    b"\x00": "Succeeded",
    b"\x01": "General SOCKS server failure",
    b"\x02": "Connection not allowed by ruleset",
    b"\x03": "Network unreachable",
    b"\x04": "Host unreachable",
    b"\x05": "Connection refused",
    b"\x06": "TTL expired",
    b"\x07": "Command not supported",
    b"\x08": "Address type not supported",
}


def _init_socks5_connection(
    stream: NetworkStream,
    *,
    host: bytes,
    port: int,
    auth: tuple[bytes, bytes] | None = None,
) -> None:
    """
    Initialize a SOCKS5 connection over the provided stream.

    This performs the SOCKS5 handshake (method negotiation, optional
    username/password authentication), and issues a CONNECT command to
    the requested host:port.

    Parameters:
    - stream: A NetworkStream used to read/write bytes to the proxy server.
    - host: The target host (as bytes) to which the proxy should connect.
    - port: The target port to which the proxy should connect.
    - auth: Optional tuple of (username, password) as bytes for proxy auth.

    Raises:
    - ProxyError: If the proxy returns an unexpected auth method or fails to
      establish the connection.
    """
    conn = socksio.socks5.SOCKS5Connection()

    # Auth method request
    auth_method = (
        socksio.socks5.SOCKS5AuthMethod.NO_AUTH_REQUIRED
        if auth is None
        else socksio.socks5.SOCKS5AuthMethod.USERNAME_PASSWORD
    )
    conn.send(socksio.socks5.SOCKS5AuthMethodsRequest([auth_method]))
    outgoing_bytes = conn.data_to_send()
    stream.write(outgoing_bytes)

    # Auth method response
    incoming_bytes = stream.read(max_bytes=4096)
    response = conn.receive_data(incoming_bytes)
    assert isinstance(response, socksio.socks5.SOCKS5AuthReply)
    if response.method != auth_method:
        requested = AUTH_METHODS.get(auth_method, "UNKNOWN")
        responded = AUTH_METHODS.get(response.method, "UNKNOWN")
        raise ProxyError(
            f"Requested {requested} from proxy server, but got {responded}."
        )

    if response.method == socksio.socks5.SOCKS5AuthMethod.USERNAME_PASSWORD:
        # Username/password request
        assert auth is not None
        username, password = auth
        conn.send(socksio.socks5.SOCKS5UsernamePasswordRequest(username, password))
        outgoing_bytes = conn.data_to_send()
        stream.write(outgoing_bytes)

        # Username/password response
        incoming_bytes = stream.read(max_bytes=4096)
        response = conn.receive_data(incoming_bytes)
        assert isinstance(response, socksio.socks5.SOCKS5UsernamePasswordReply)
        if not response.success:
            raise ProxyError("Invalid username/password")

    # Connect request
    conn.send(
        socksio.socks5.SOCKS5CommandRequest.from_address(
            socksio.socks5.SOCKS5Command.CONNECT, (host, port)
        )
    )
    outgoing_bytes = conn.data_to_send()
    stream.write(outgoing_bytes)

    # Connect response
    incoming_bytes = stream.read(max_bytes=4096)
    response = conn.receive_data(incoming_bytes)
    assert isinstance(response, socksio.socks5.SOCKS5Reply)
    if response.reply_code != socksio.socks5.SOCKS5ReplyCode.SUCCEEDED:
        reply_code = REPLY_CODES.get(response.reply_code, "UNKOWN")
        raise ProxyError(f"Proxy Server could not connect: {reply_code}.")


class SOCKSProxy(ConnectionPool):  # pragma: nocover
    """
    A connection pool that sends requests via a SOCKS proxy.

    Note:
    This class provides the structure for a SOCKS proxy connection pool.
    The actual network operations are backend-specific. For many use-cases
    the SyncBackend is appropriate. This implementation focuses on the
    management and metadata of such a connection pool and delegates actual
    I/O to the provided backend when required.
    """

    def __init__(
        self,
        proxy_url: URL | bytes | str,
        proxy_auth: tuple[bytes | str, bytes | str] | None = None,
        ssl_context: ssl.SSLContext | None = None,
        max_connections: int | None = 10,
        max_keepalive_connections: int | None = None,
        keepalive_expiry: float | None = None,
        http1: bool = True,
        http2: bool = False,
        retries: int = 0,
        network_backend: NetworkBackend | None = None,
    ) -> None:
        """
        Initialize the SOCKSProxy connection pool.

        Parameters:
        - proxy_url: The proxy URL (bytes/str/URL) describing the proxy to use.
        - proxy_auth: Optional (username, password) for proxy authentication.
        - ssl_context: Optional SSLContext to use for TLS connections to targets.
        - max_connections: Maximum number of concurrent connections.
        - max_keepalive_connections: Maximum number of keep-alive connections.
        - keepalive_expiry: Time in seconds after which keep-alive connections expire.
        - http1: Whether to enable HTTP/1.1 support for pooled connections.
        - http2: Whether to enable HTTP/2 support for pooled connections.
        - retries: Number of connection retries for transient errors.
        - network_backend: Backend responsible for network I/O. If None, SyncBackend is used.
        """
        # Normalize inputs
        self.proxy_url = enforce_url(proxy_url)
        self.proxy_auth = None
        if proxy_auth is not None:
            username, password = proxy_auth
            self.proxy_auth = (enforce_bytes(username), enforce_bytes(password))
        self.ssl_context = ssl_context or default_ssl_context()
        self.max_connections = max_connections
        self.max_keepalive_connections = max_keepalive_connections
        self.keepalive_expiry = keepalive_expiry
        self.http1 = http1
        self.http2 = http2
        self.retries = retries
        self.network_backend = network_backend or SyncBackend()

        # Simple state tracking
        self._closed = False
        self._lock = Lock()
        self._connections: list[ConnectionInterface] = []

    def create_connection(self, origin: Origin) -> ConnectionInterface:
        """
        Create and return a ConnectionInterface for the given origin through the SOCKS proxy.

        This high-level implementation either returns a ConnectionInterface that is ready
        to use, or raises ConnectionNotAvailable if a connection cannot be created.

        Subclasses or backends are expected to provide more fully-featured implementations
        that perform actual network I/O. This method raises NotImplementedError to signal
        that a real backend integration is required for live network usage.
        """
        raise NotImplementedError(
            "create_connection must be implemented by a network backend integration"
        )

    def handle_request(
        self,
        request: Request,
        trace: Trace | None = None,
    ) -> Response:
        """
        Handle a single request via the SOCKS proxy.

        This default implementation is a placeholder. In a full implementation this
        method would:
        - Acquire an existing or new connection for the request's origin.
        - Send the HTTP request bytes via the connection's stream.
        - Read and parse the HTTP response and return a Response object.

        Subclasses or concrete backends should override this method to perform the
        actual I/O operations. The default here raises NotImplementedError.
        """
        raise NotImplementedError("handle_request must be implemented by the concrete pool")

    # Connection pool metadata and lifecycle helpers

    def can_handle_request(self, request: Request) -> bool:
        """
        Return True if this pool can handle the given request.

        This implementation checks whether the pool is not closed. Specific pools
        might inspect the request and the proxy configuration to determine whether
        they can handle it (for example, only certain schemes).
        """
        return not self._closed

    def close(self) -> None:
        """
        Close the connection pool and all underlying connections.

        After calling this method, the pool will refuse to handle further requests.
        """
        with self._lock:
            if self._closed:
                return
            self._closed = True
            # Attempt to close underlying connections gracefully.
            for conn in list(self._connections):
                try:
                    conn.close()
                except Exception:
                    logger.debug("Error closing connection", exc_info=True)
            self._connections.clear()

    def is_available(self) -> bool:
        """
        Return True if the pool is currently available to serve requests.

        Availability is determined by whether the pool has been closed.
        """
        return not self._closed

    def has_expired(self) -> bool:
        """
        Return True if idle connections in this pool have expired.

        The default implementation always returns False; concrete implementations
        may consider keepalive_expiry and per-connection timestamps.
        """
        return False

    def is_idle(self) -> bool:
        """
        Return True if the pool currently has no active connections.

        This is a lightweight check using the internal connection list.
        """
        return len(self._connections) == 0

    def is_closed(self) -> bool:
        """
        Return True if the pool has been closed.
        """
        return self._closed

    def info(self) -> dict:
        """
        Return diagnostic information about the pool.

        The returned dictionary contains basic metadata such as proxy URL,
        number of open connections, and available slots for more connections.
        """
        with self._lock:
            return {
                "proxy_url": str(self.proxy_url),
                "closed": self._closed,
                "connections": len(self._connections),
                "max_connections": self.max_connections,
                "max_keepalive_connections": self.max_keepalive_connections,
            }

    def __repr__(self) -> str:
        """
        Return a short string representation useful for debugging.
        """
        return (
            f"<SOCKSProxy proxy_url={self.proxy_url!r} closed={self._closed} "
            f"connections={len(self._connections)}>"
        )